import {
  CHANGE,
  ARTICLEADD,
  LOVEARTICLEADD,
  LIVEARTICLEADD,
  TOPARTICLEADD
} from "./mutation_type";

export default {
  [CHANGE](state,str){
    state.demo += str;
  },
  [ARTICLEADD](state,data){
    state.articles = state.articles.concat(data);
  },
  [LOVEARTICLEADD](state,data){
    state.love_articles = state.love_articles.concat(data);
  },
  [LIVEARTICLEADD](state,data){
    state.live_articles = state.live_articles.concat(data);
  },
  [TOPARTICLEADD](state,data){
    state.top_articles = state.top_articles.concat(data);
  },
}



