<template>
  <div id="app">
    <headers></headers>
    <div class="banner" :style="{backgroundImage:'url('+img+')'}">
      <p style="height: 160px;line-height: 160px;margin-left: 80px;font-size: 36px;color: #969799;margin-top: -20px">{{headTitle}}</p>
    </div>
    <!--<div class="content-wapper cl">-->
      <!--<div class="siderbar-wapper">-->
        <!--<siderbar></siderbar>-->
      <!--</div>-->
      <!--<div class="route-wapper cl">-->
        <!--<router-view></router-view>-->
      <!--</div>-->
      <div class="container" style="margin-top: 50px">
        <div class="row">
          <div class="col-md-3"><siderbar></siderbar></div>
          <div class="col-md-9">
            <router-view></router-view>
          </div>
        </div>
      </div>
    </div>
</template>

<script>
  import headers from './components/Headers'
  import siderbar from './components/SiderBar'
  import axios from 'axios'
  export default {
    name: 'App',
    data(){
      return{
        headTitle:'',
        img: require('./assets/girl.jpeg')
      }
    },
    components: {
      headers,siderbar
    },
    created(){
      axios.get(this.$store.state.domain+'gettitle').then((res)=>{
          this.headTitle = res.data;
      })
    },
    methods: {

    }

  }
</script>

<style scoped lang="stylus" ref="stylesheet/stylus">
  .banner{
    margin-top:60px;
    height: 160px;
    background-color: #f5f5f5;
  }
</style>



