<template>

  <div class="panel panel-default" v-if="article == 'no'">
    <div class="panel-heading" style="text-align: center;font-size: 22px">
      没有相关文章
    </div>
    <div class="panel-body">

      <div class="content">

      </div>
    </div>
  </div>

  <div class="panel panel-default" v-else>
    <div class="panel-heading" style="text-align: center;font-size: 22px">
      {{article.title}}
    </div>
    <div class="panel-body">
      <div class="article-introduce"><span>作者：{{article.author}}</span><span style="margin-left: 20px">发布时间：{{article.created_at}}</span><span style="margin-left: 20px">tags:{{article.tags}}</span></div>
      <div v-html="article.content" class="content">
      </div>
      <div class="article-bottom-box">
          <div v-if="preAticle == null"><div class="prev-article"><p>没有上一篇了</p></div></div>
          <div v-else><div class="prev-article"><button class="btn btn-defult" @click="routeTo('../'+preAticle.path)"><p>上一篇：{{preAticle.title}}</p></button></div></div>
          <div v-if="nextAticle == null"><div class="next-article"><p>没有下一篇了</p></div></div>
          <div v-else><div class="next-article"><button class="btn btn-defult" @click="routeTo('../'+nextAticle.path)"><p>{{nextAticle.title}}:下一篇</p></button></div></div>
      </div>
    </div>
  </div>


</template>

<script>
  import axios from 'axios'
    export default {
        name: "articles",
        data(){
          return{
            article:[],
            preAticle:null,
            nextAticle:null,
          }
        },
        created() {
          console.log(this.$route.params.id);
          var that = this;
          if (this.$store.state.articles.length == 0) {
            axios.get(this.$store.state.domain + 'service/post', {
              params:{
                  id:this.$route.params.id
              }
            }).then((res) => {
              this.article = res.data[0];
              this.preAticle = res.data[1];
              this.nextAticle = res.data[2];
            });

          } else {
            for (var i = 0, len = that.$store.state.articles.length; i < len; i++) {
              let path = that.$route.path.substr(1);
              if (that.$store.state.articles[i].path == path) {
                that.article = that.$store.state.articles[i];
                that.preAticle = that.$store.state.articles[i - 1];
                that.nextAticle = that.$store.state.articles[i + 1];
                console.log(that.nextAticle.path);
              }
            }
          }
        },
        methods:{
          routeTo(path){
            this.$router.replace(path);
            this.$router.go(0);
          }
        }
    }
</script>

<style lang="stylus" ref="stylesheet/stylus" scoped>
    .article-introduce
      text-align center
      span
        color #969799
    .content
      margin-top 20px
    .article-bottom-box
      margin 10px 10px
      .prev-article
       float left
      .next-article
        float: right
</style>



