//1.引入router模块
import Vue from 'vue';
import VueRouter from 'vue-router';
import Home from './../vue/Home/Home';
import Search from './../vue/Search/Search';
import Articles from './../vue/Article/Articles';
import Tag from './../vue/Tag/Tag';
import Like from './../vue/Like/Like'
import Aboutme from './../vue/Aboutme/Aboutme'
import Live from './../vue/Live/Live'
//2.用vue声明使用
Vue.use(VueRouter);

//3.输出路由对象
export default new VueRouter({

  routes:[
    {
      path:'/',
      redirect:'/home'
    },
    {
      path:'/home',
      component:Home,
      children:[
        {
          path:'demo',
          component:Search
        }
      ]
    },
    {
      path:'/like',
      component:Like
    },
    {
      path:'/aboutme',
      component:Aboutme
    },
    {
      path:'/live',
      component:Live
    },
    {
      path:'/post/:id',
      component:Articles
    },
    {
      path:'/Tag/:tag',
        component:Tag
    }
  ]

});

