<template>
  <div class="panel panel-default" style="border-top: 3px solid #f4645f">
    <div class="panel-heading">
      生活类文章
    </div>
    <div class="panel-body">
      <div style="margin: 10px;">
        <!--文章列表循环输出-->
        <div class="media" style="border-top: 1px solid #ccc" v-for="(item,index) in $store.state.live_articles" :key="index">
          <div style="margin-top: 5px">
            <div class="media-left">
              <img :src="item.thumb" class="media-object" style="width:60px">
            </div>
            <div class="media-body">
              <h4 class="media-heading" style="overflow: hidden;height: 18px">
                <router-link style="text-decoration: none" :to="'../'+item.path">{{item.title}}</router-link>
              </h4>
              <p style="overflow: hidden;height: 20px">{{item.summary}}</p>
              <div>
                <span style="color: #969799">发布日期：{{item.created_at}}</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
  import axios from 'axios';

  export default {
    name: "live",
    data() {
      var that = this;
      return {
        page: 0,
        articles: []
      }
    },
    watch: {
      articles() {
        this.$nextTick(() => {
          // 让当前的页码+1
          this.page += 1;
          // 初始化
          this.touch_end();
        })
      }
    },
    created() {
      axios.get(this.$store.state.domain + 'test5', {
        params: {
          page: this.page
        }
      }).then((res) => {
        this.$store.dispatch('liveArticleAdd',res.data)
      })
    },
    mounted() {
      // this.touch_end()
    },
    methods: {
      touch_end(){
        var that = this;

        var scrollTimer;

        window.onscroll = function () {
          clearTimeout(scrollTimer);
          scrollTimer = setTimeout(()=>{
            var scrollTop = $(this).scrollTop();
            var scrollHeight = $(document).height();
            var windowHeight = $(window).height()+50;
            if (scrollTop+windowHeight >= scrollHeight){
              axios.get(that.$store.state.domain+'test5',{
                params:{
                  page:that.page
                }
              }).then((res)=>{
                if (res.data == ''){
                  return;
                }else{
                  that.$store.dispatch('liveArticleAdd',res.data);
                }
              })
            }
          },300)
        }
      },
    }
  }
</script>

<style scoped lang="stylus" ref="stylesheet/stylus">

</style>



